/**
 * Utility service for handling testimonial submissions
 * In a real application, this would connect to a backend API
 */

// Store testimonials in localStorage for demo purposes
const STORAGE_KEY = 'harsh_portfolio_testimonials';

/**
 * Get all testimonials
 * @returns {Array} Array of testimonial objects
 */
export const getTestimonials = () => {
  try {
    const storedTestimonials = localStorage.getItem(STORAGE_KEY);
    return storedTestimonials ? JSON.parse(storedTestimonials) : [];
  } catch (error) {
    console.error('Error getting testimonials:', error);
    return [];
  }
};

/**
 * Add a new testimonial
 * @param {Object} testimonial - The testimonial data
 * @returns {Promise} Promise that resolves when testimonial is added
 */
export const addTestimonial = async (testimonial) => {
  try {
    // In a real app, this would be an API call
    // Simulate network request
    await new Promise(resolve => setTimeout(resolve, 1000));
    
    // Add timestamp and ID
    const newTestimonial = {
      ...testimonial,
      id: Date.now().toString(),
      createdAt: new Date().toISOString(),
      // In a real system, this would be pending approval
      status: 'pending'
    };
    
    // Get existing testimonials
    const testimonials = getTestimonials();
    
    // Add new testimonial
    testimonials.push(newTestimonial);
    
    // Save to localStorage
    localStorage.setItem(STORAGE_KEY, JSON.stringify(testimonials));
    
    return newTestimonial;
  } catch (error) {
    console.error('Error adding testimonial:', error);
    throw new Error('Failed to add testimonial');
  }
};

/**
 * In a real application, these functions would also be implemented:
 * - approveTestimonial
 * - deleteTestimonial
 * - editTestimonial
 */
